oxy_webhelp_navlinks = {"azr_workloads_protection_setup-d27248e18024":{"topics":[{"title":"SLA Domain assignment hierarchy for Azure","shortdesc":"<p class=\"shortdesc\">In <span class=\"ph\">RSC<\/span>, SLA Domain assignments for Azure workloads follow a scope         hierarchy from subscription (broadest) to individual workload (most specific), where         lower-level assignments override higher-level ones, and tag-based and direct assignments         provide additional override mechanisms.<\/p>","href":"saas\/azr_hierarchy_sla_assignment.html","attributes":{"data-id":"azr_hierarchy_sla_assignment"},"menu":{"hasChildren":false},"tocID":"azr_hierarchy_sla_assignment-d27248e18035","topics":[]},{"title":"Best practices for Azure SLA Domain assignment","shortdesc":"<p class=\"shortdesc\">Information about the best practices for assigning SLA Domains to Azure workloads,         ensuring effective data protection and compliance.<\/p>","href":"saas\/azr_best_practices_sla_assignment.html","attributes":{"data-id":"azr_best_practices_sla_assignment"},"menu":{"hasChildren":false},"tocID":"azr_best_practices_sla_assignment-d27248e18049","topics":[]},{"title":"Evaluate Azure workload protection options","shortdesc":"<p class=\"shortdesc\">Understanding the various protection options is important when creating an SLA Domain         for your Azure workloads. This ensures alignment with organizational needs. Thoroughly         evaluating these options enables taking informed decision and providing effective protection         for the workloads.<\/p>","href":"saas\/azr_evaluate_options_workload_protect.html","attributes":{"data-id":"azr_evaluate_options_workload_protect"},"menu":{"hasChildren":false},"tocID":"azr_evaluate_options_workload_protect-d27248e18060","next":"azr_evaluate_options_workload_protect-d27248e18060"},{"title":"Region-level SLA Domain assignment for Azure","shortdesc":"<p class=\"shortdesc\">You can apply a unified policy to an entire Azure region with a region-level SLA         Domain assignment, ensuring any new resource in that region is automatically         protected.<\/p>","href":"saas\/azr_region_level_sla_assignment.html","attributes":{"data-id":"azr_region_level_sla_assignment"},"menu":{"hasChildren":false},"tocID":"azr_region_level_sla_assignment-d27248e18134","topics":[]},{"title":"Configure Azure protection","shortdesc":"<p class=\"shortdesc\">After you have decided on the protection policies you want to configure, you can         begin the protection setup by creating an SLA Domain and assigning protection to workloads,         resource groups, and subscriptions.<\/p>","href":"saas\/azr_protection_config.html","attributes":{"data-id":"azr_protection_config"},"menu":{"hasChildren":false},"tocID":"azr_protection_config-d27248e18145","next":"azr_protection_config-d27248e18145"}]}};